  1	import * as React from 'react';
  2	import {
  3	  LifecycleRule,
  4	  GetBucketLifecycleConfigurationCommandOutput,
  5	} from '@aws-sdk/client-s3';
  6	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  7	import { CommonModalProps } from '@odf/shared/modals';
  8	import { S3Commands } from '@odf/shared/s3';
  9	import { isNoLifecycleRuleError } from '@odf/shared/s3/utils';
 10	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 11	import { deepSortObject } from '@odf/shared/utils';
 12	import { murmur3 } from 'murmurhash-js';
 13	import { KeyedMutator } from 'swr';
 14	import {
 15	  Modal,
 16	  ModalVariant,
 17	  Button,
 18	  ButtonVariant,
 19	} from '@patternfly/react-core';
 20	
 21	type DeleteLifecycleRuleModalProps = {
 22	  mutate: KeyedMutator<GetBucketLifecycleConfigurationCommandOutput>;
 23	  s3Client: S3Commands;
 24	  bucketName: string;
 25	  ruleName: string;
 26	  ruleHash: number;
 27	};
 28	
 29	const getUpdatedRules = (
 30	  latestRules: GetBucketLifecycleConfigurationCommandOutput,
 31	  ruleName: string,
 32	  ruleHash: number
 33	) => {
 34	  let filteredRules: LifecycleRule[];
 35	  if (!!ruleName) {
 36	    filteredRules =
 37	      latestRules?.Rules?.filter((rule) => rule.ID !== ruleName) || [];
 38	  } else if (!!ruleHash) {
 39	    // fallback if rule name (ID) is missing
 40	    filteredRules =
 41	      latestRules?.Rules?.filter(
 42	        (rule) => murmur3(JSON.stringify(deepSortObject(rule))) !== ruleHash
 43	      ) || [];
 44	  } else {
 45	    filteredRules = latestRules?.Rules || [];
 46	  }
 47	
 48	  return filteredRules;
 49	};
 50	
 51	const DeleteLifecycleRuleModal: React.FC<
 52	  CommonModalProps<DeleteLifecycleRuleModalProps>
 53	> = ({
 54	  closeModal,
 55	  isOpen,
 56	  extraProps: { s3Client, bucketName, mutate, ruleName, ruleHash },
 57	}) => {
 58	  const { t } = useCustomTranslation();
 59	
 60	  const [inProgress, setInProgress] = React.useState<boolean>(false);
 61	  const [error, setError] = React.useState<Error>();
 62	
 63	  const onDelete = async (event) => {
 64	    event.preventDefault();
 65	    setInProgress(true);
 66	
 67	    try {
 68	      let latestRules: GetBucketLifecycleConfigurationCommandOutput;
 69	
 70	      try {
 71	        latestRules = await s3Client.getBucketLifecycleConfiguration({
 72	          Bucket: bucketName,
 73	        });
 74	      } catch (err) {
 75	        if (isNoLifecycleRuleError(err)) {
 76	          latestRules = {
 77	            Rules: [],
 78	          } as GetBucketLifecycleConfigurationCommandOutput;
 79	        } else {
 80	          throw err;
 81	        }
 82	      }
 83	
 84	      // `{ LifecycleConfiguration: { Rules: [] } }` syntax is being interpreted as an attempt to update Lifecycle config (not delete) with an invalid payload (no rules),
 85	      // so the endpoint is throwing a 500 error.
 86	      // Hence using "deleteBucketLifecycle" for such cases where we need to cleanup entire Lifecycle configuration.
 87	      const updatedLifecycleRules = getUpdatedRules(
 88	        latestRules,
 89	        ruleName,
 90	        ruleHash
 91	      );
 92	      if (!!updatedLifecycleRules?.length)
 93	        await s3Client.putBucketLifecycleConfiguration({
 94	          Bucket: bucketName,
 95	          LifecycleConfiguration: {
 96	            Rules: updatedLifecycleRules,
 97	          },
 98	        });
 99	      else await s3Client.deleteBucketLifecycle({ Bucket: bucketName });
100	
101	      setInProgress(false);
102	      mutate();
103	      closeModal();
104	    } catch (err) {
105	      setInProgress(false);
106	      setError(err);
107	    }
108	  };
109	
110	  return (
111	    <Modal
112	      title={t('Delete lifecycle rule?')}
113	      titleIconVariant="warning"
114	      isOpen={isOpen}
115	      onClose={closeModal}
116	      description={
117	        <div className="text-muted">
118	          {t(
119	            'Deleting this lifecycle rule may prevent the removal of existing objects, potentially increasing storage costs.'
120	          )}
121	        </div>
122	      }
123	      variant={ModalVariant.medium}
124	      actions={[
125	        <ButtonBar
126	          inProgress={inProgress}
127	          errorMessage={error?.message || JSON.stringify(error)}
128	        >
129	          <span>
130	            <Button
131	              variant={ButtonVariant.danger}
132	              onClick={onDelete}
133	              isDisabled={!!error || inProgress}
134	              className="pf-v6-u-mr-xs"
135	            >
136	              {t('Delete')}
137	            </Button>
138	            <Button
139	              variant={ButtonVariant.link}
140	              onClick={closeModal}
141	              className="pf-v6-u-ml-xs"
142	            >
143	              {t('Cancel')}
144	            </Button>
145	          </span>
146	        </ButtonBar>,
147	      ]}
148	    >
149	      {' '}
150	    </Modal>
151	  );
152	};
153	
154	export default DeleteLifecycleRuleModal;

